import React, { useEffect, useState } from "react";
import axios from "axios";

function AverageSalary() {
  const [data, setData] = useState(null);

  useEffect(() => {
    // ✅ Get full user object
    const user = JSON.parse(localStorage.getItem("user"));

    console.log("User:", user);

    // ✅ Check email exists
    if (!user || !user.email) {
      console.log("No email found in localStorage");
      return;
    }

    const email = user.email;

    console.log("Sending email:", email);

    // ✅ Correct API call
    axios
      .get(`http://localhost:5000/api/average-salary/${email}`)
      .then(res => {
        console.log("API Response:", res.data);
        setData(res.data);
      })
      .catch(err => console.log(err));
  }, []);

  // ✅ Loading state
  if (!data) return <h2>Loading...</h2>;

  return (
    
    <div style={{ padding: "20px" }}>
      <h1>Average Salary</h1>

      <h2>₹{data.average?.toFixed(0)}</h2>

      <p>Highest: ₹{data.highest}</p>
      <p>Lowest: ₹{data.lowest}</p>
      <p>Total Predictions: {data.total}</p>

      <h3>Recent Salaries:</h3>
      <ul>
        {data.recent?.map((s, i) => (
          <li key={i}>₹{s}</li>
        ))}
      </ul>
    </div>
  );
}

export default AverageSalary;
